code.perFrame:
zoom = 1;
rot = 0;
dx = 0;
dy = 0;
sx = 1;
sy = 1;
warp = 0.001;
cx = 0.5;
cy = 0.5;
vol = vol*.9+(treb+mid+bass)*.033;;
//dx = (int(rand(10))-5)*.02*vol;;
rr = rr +(int(rand(10))-5)*.01*vol*sign(rr);;
rot = rr;;
wave_g = (dx)*3;;
wave_r = (dy)*3;;
cx = .5+sin(time*.211)*.3;;
cy = .5-sin(time*.205)*.3;;
wave_x  = cx;;
wave_y = 1-cy;;
decay = -((rr) > (.1))*.1+decay;;
monitor = decay;

code.perVertex:
ca = atan((y-cy)/(x-cx))+3.14159*((x) < (cx));;
cr = pow((y-cy)*(y-cy)+(x-cx)*(x-cx), .5);;
bb = bass*bass*treb*cr*.01;;
dx =bb*cos(ca);;
dy = bb*sin(ca);
